import { useEffect, useState, useRef } from "react";
import { useParams, Link } from "react-router-dom";
import { io } from "socket.io-client";
import api from "../services/api";
import toast from "react-hot-toast";

export default function ItemDetail() {

  const { id } = useParams();

  const [item, setItem] = useState(null);
  const [answers, setAnswers] = useState([]);
  const [myClaim, setMyClaim] = useState(null);
  const [messages, setMessages] = useState([]);
  const [messageInput, setMessageInput] = useState("");
  const [loading, setLoading] = useState(true);

  const socketRef = useRef(null);
  const messagesEndRef = useRef(null);

  const accessToken = localStorage.getItem("accessToken");
  const isLoggedIn = Boolean(accessToken);

  const user = JSON.parse(localStorage.getItem("user") || "null");
  const loggedInUserId = user?._id || null;

  /* ================= LOAD ITEM ================= */

  useEffect(() => {

    const loadItem = async () => {

      try {

        const res = await api.get(`/items/${id}`);

        setItem(res.data);

        setAnswers(
          res.data.verificationQuestions?.map(() => "") || []
        );

        if (res.data.claims && loggedInUserId) {

          const claim = res.data.claims.find(
            c =>
              (typeof c.userId === "string"
                ? c.userId
                : c.userId?._id) === loggedInUserId
          );

          if (claim) setMyClaim(claim);

        }

      } catch {

        toast.error("Failed to load item");

      } finally {

        setLoading(false);

      }

    };

    loadItem();

  }, [id]);

  /* ================= SOCKET CHAT ================= */

  useEffect(() => {

    if (!isLoggedIn) return;

    socketRef.current = io("http://localhost:5000", {
      auth: {
        token: accessToken
      }
    });

    const socket = socketRef.current;

    socket.emit("join_room", id);

    api.get(`/items/${id}/chat`)
      .then(res => setMessages(res.data))
      .catch(() => {});

    socket.on("receive_message", data => {
      setMessages(prev => [...prev, data]);
    });

    return () => {
      socket.disconnect();
    };

  }, [id, accessToken, isLoggedIn]);

  const sendMessage = () => {

    if (!messageInput.trim()) return;

    socketRef.current.emit("send_message", {
      roomId: id,
      text: messageInput
    });

    setMessageInput("");

  };

  useEffect(() => {

    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });

  }, [messages]);

  /* ================= CLAIM ================= */

  const submitClaim = async e => {

    e.preventDefault();

    if (answers.some(a => !a.trim())) {

      toast.error("Please answer all questions");
      return;

    }

    try {

      const res = await api.post(`/items/${id}/claim`, { answers });

      toast.success(`Confidence: ${res.data.confidence}%`);

      window.location.reload();

    } catch (err) {

      toast.error(err.response?.data?.message || "Claim failed");

    }

  };

  if (loading) {

    return (
      <div className="h-screen flex items-center justify-center text-xl">
        Loading...
      </div>
    );

  }

  if (!item) {

    return (
      <div className="h-screen flex items-center justify-center">
        Item not found
      </div>
    );

  }

  const isOwner =
    loggedInUserId &&
    (typeof item.user === "string"
      ? item.user
      : item.user?._id) === loggedInUserId;

  const canChat =
    isOwner ||
    (myClaim && myClaim.status === "approved");

  /* ================= UI ================= */

  return (

    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-gray-100 p-8">

      <div className="max-w-5xl mx-auto bg-white rounded-3xl shadow-xl overflow-hidden">

        {item.images?.length > 0 && (

          <div className="relative">

            <img
              src={`http://localhost:5000/${item.images[0]}`}
              alt={item.title}
              className="w-full h-96 object-cover"
            />

            <span
              className={`absolute top-4 left-4 px-4 py-2 rounded-full text-sm font-bold shadow
              ${item.type === "lost"
                ? "bg-red-500 text-white"
                : "bg-green-500 text-white"}`}
            >
              {item.type.toUpperCase()}
            </span>

          </div>

        )}

        <div className="p-8 space-y-6">

          <Link to="/dashboard" className="text-blue-600 text-sm">
            ← Back to Dashboard
          </Link>

          <h1 className="text-4xl font-bold text-gray-800">
            {item.title}
          </h1>

          <p className="text-gray-600 text-lg">
            {item.description}
          </p>

          {/* OWNER DASHBOARD */}

          {isOwner && (

            <div className="bg-indigo-50 border border-indigo-200 p-6 rounded-xl">

              <h2 className="text-xl font-bold text-indigo-700">
                Owner Dashboard
              </h2>

              <p className="text-gray-600 mt-2">
                Your item is visible to users who may submit claims.
              </p>

              <div className="flex gap-4 mt-4">

                <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-sm">
                  Status: {item.status}
                </span>

                <span className="bg-purple-100 text-purple-700 px-3 py-1 rounded-full text-sm">
                  Claims: {item.claims?.length || 0}
                </span>

              </div>

            </div>

          )}

          {item.contact && (

            <div className="bg-green-50 border border-green-200 p-4 rounded-xl">

              <p className="text-sm text-gray-500">
                Contact Information
              </p>

              <p className="text-xl font-semibold text-green-700">
                {item.contact}
              </p>

            </div>

          )}

          {canChat && (

            <div className="border-t pt-6">

              <h2 className="text-2xl font-bold mb-4">
                Private Chat
              </h2>

              <div className="h-80 overflow-y-auto bg-gray-50 p-4 rounded-xl space-y-3">

                {messages.map((msg, i) => (

                  <div
                    key={i}
                    className={`flex ${
                      msg.sender === loggedInUserId
                        ? "justify-end"
                        : "justify-start"
                    }`}
                  >

                    <div
                      className={`px-4 py-2 rounded-2xl max-w-xs ${
                        msg.sender === loggedInUserId
                          ? "bg-blue-600 text-white"
                          : "bg-gray-200"
                      }`}
                    >

                      {msg.text}

                      <div className="text-xs opacity-60 mt-1">
                        {msg.time}
                      </div>

                    </div>

                  </div>

                ))}

                <div ref={messagesEndRef} />

              </div>

              <div className="flex gap-3 mt-4">

                <input
                  value={messageInput}
                  onChange={e => setMessageInput(e.target.value)}
                  placeholder="Type a message..."
                  className="flex-1 border rounded-xl px-4 py-2"
                />

                <button
                  onClick={sendMessage}
                  className="bg-blue-600 text-white px-6 rounded-xl"
                >
                  Send
                </button>

              </div>

            </div>

          )}

        </div>

      </div>

    </div>

  );

}
